// Parse the JSON string returned by OpenAI
const raw = $input.item.json.message.content.trim();

let parsed;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { category: 'Other', priority: 'Low', summary: raw, emoji: '📧' };
}

// Gmail simple:true returns capitalized flat fields (Subject, From)
// Gmail simple:false returns nested objects (from.value[0].address)
// Support both with fallbacks
const email = $('New Email Arrives').item.json;
const subject = email.Subject ?? email.subject ?? '(no subject)';
const from = email.From ?? email.from?.value?.[0]?.address ?? '(unknown sender)';
const date = email.Date ?? email.date ?? new Date().toISOString();

return [{
  json: {
    ...parsed,
    subject,
    from,
    date
  }
}];
